import rclpy
from rclpy.node import Node
from sensor_msgs.msg import Image
from cv_bridge import CvBridge
import cv2
import numpy as np

class TrafficMonitor(Node):
    def __init__(self):
        super().__init__('traffic_monitor')
        self.bridge = CvBridge()
        
        # Subscribe to camera and debug mask
        self.create_subscription(Image, '/front_camera/image_raw', self.camera_callback, 10)
        self.create_subscription(Image, '/traffic_light/debug_image', self.debug_callback, 10)
        
        self.cam_frame = None
        self.debug_frame = None
        
        self.get_logger().info('Traffic Monitor Started. Windows will open when data arrives.')

    def camera_callback(self, msg):
        self.cam_frame = self.bridge.imgmsg_to_cv2(msg, "bgra8")
        self.show()

    def debug_callback(self, msg):
        self.debug_frame = self.bridge.imgmsg_to_cv2(msg, "mono8")
        self.show()

    def show(self):
        if self.cam_frame is not None:
            cv2.imshow("Front Camera", self.cam_frame)
        if self.debug_frame is not None:
            # Resize debug mask to match cam for better comparison
            debug_resized = cv2.resize(self.debug_frame, (400, 200))
            cv2.imshow("Traffic Light Detection (Mask)", debug_resized)
        
        cv2.waitKey(1)

def main():
    rclpy.init()
    node = TrafficMonitor()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        cv2.destroyAllWindows()
        node.destroy_node()
        rclpy.shutdown()

if __name__ == '__main__':
    main()
